K=$(grep -E '^N8N_API_KEY=' /root/Iryna_Karmazina/.env | tail -1 | cut -d= -f2-)
python3 - "$K" << 'PYEOF'
import json,sys,re,urllib.request,urllib.error
K=sys.argv[1]
BASE='https://irynakarmazina.app.n8n.cloud/api/v1/workflows/'
blue_new="const blue=['Стафіровка','В порту відправлення','Завантажений на судно','В морі','Зданий в порт','Завантажений на потяг','Завантажений на авто'];"
purple_new="const purple=['Вивантажений в порту прибуття','Завантажений на авто/потяг','Прибув в сухій порт'];"
def GET(w):
    return json.load(urllib.request.urlopen(urllib.request.Request(BASE+w,headers={'X-N8N-API-KEY':K}),timeout=30))
for WID,label in [('1YdXnLFOXI85IsWv','dashboard'),('VGi9phda7zLZC9eD','portal')]:
    try:
        d=GET(WID)
    except Exception as e:
        print(label,'GET ERR',e); continue
    open('/root/wf-backup-'+WID+'.json','w').write(json.dumps(d))
    patched=0
    for n in d['nodes']:
        if n.get('type')=='n8n-nodes-base.code':
            c=(n.get('parameters') or {}).get('jsCode','')
            if 'const blue=' in c:
                c2=re.sub(r"const blue=\[[^\]]*\];",blue_new,c,count=1)
                c2=re.sub(r"const purple=\[[^\]]*\];",purple_new,c2,count=1)
                if c2!=c:
                    n['parameters']['jsCode']=c2; patched+=1
    payload={'name':d['name'],'nodes':d['nodes'],'connections':d['connections'],'settings':d.get('settings',{})}
    if d.get('staticData') is not None: payload['staticData']=d['staticData']
    body=json.dumps(payload).encode('utf-8')
    try:
        r=urllib.request.urlopen(urllib.request.Request(BASE+WID,data=body,method='PUT',headers={'X-N8N-API-KEY':K,'Content-Type':'application/json'}),timeout=40)
        put=r.status
    except urllib.error.HTTPError as e:
        put=str(e.code)+' '+e.read()[:200].decode('utf-8','ignore')
    try:
        urllib.request.urlopen(urllib.request.Request(BASE+WID+'/activate',method='POST',headers={'X-N8N-API-KEY':K}),timeout=20); act='ok'
    except Exception as e: act='err'
    try:
        d2=GET(WID)
        ok=any(('В порту відправлення' in (x.get('parameters') or {}).get('jsCode','')) for x in d2['nodes'] if x.get('type')=='n8n-nodes-base.code')
        active=d2.get('active')
    except Exception as e: ok='?'; active='?'
    print(label,WID,'patched:',patched,'| PUT:',put,'| activate:',act,'| verify:',ok,'| active:',active)
PYEOF
